import json
import re
import pandas as pd

patient_info_full = json.loads(open(locals()['var_function-call-14561242205782074667'], 'r').read())


def parse_patient_description(description):
    participant_barcode = None
    gender = None
    disease_type = None

    # Extract ParticipantBarcode (TCGA-XX-XXXX)
    match_barcode = re.search(r'TCGA-\d{2}-\d{4}', description)
    if match_barcode:
        participant_barcode = match_barcode.group(0)

    # Extract Gender
    if 'FEMALE' in description:
        gender = 'female'
    elif 'MALE' in description:
        gender = 'male'

    # Extract Disease Type (e.g., Ovarian serous cystadenocarcinoma, Bladder urothelial carcinoma)
    # This assumes the disease type is typically after 'diagnosed with' or 'case of'
    match_disease = re.search(r'(diagnosed with|case of|cohort of) ([A-Za-z0-9 ]+?)(?:[,.!]|$)', description)
    if match_disease:
        disease_type_str = match_disease.group(2).strip()
        if 'Ovarian serous cystadenocarcinoma' in disease_type_str:
            disease_type = 'OV'
        elif 'Bladder urothelial carcinoma' in disease_type_str:
            disease_type = 'BRCA'
        elif 'Glioblastoma multiforme' in disease_type_str:
            disease_type = 'GBM'
        else:
            disease_type = disease_type_str.replace(' dataset', '').strip() # Default to the extracted string

    return participant_barcode, gender, disease_type

processed_clinical_data = []
for record in patient_info_full:
    participant_barcode, gender, disease_type = parse_patient_description(record['Patient_description'])
    if participant_barcode and gender == 'female' and disease_type == 'BRCA' and record['histological_type'] is not None:
        processed_clinical_data.append({
            'ParticipantBarcode': participant_barcode,
            'histological_type': record['histological_type']
        })

print("__RESULT__:")
print(json.dumps(processed_clinical_data))

